import { ReactNode } from "react";
import { Dropzone, DropzoneContent, DropzoneEmptyState } from "@/components/ui/shadcn-io/dropzone";

type Props = {
  title: string;
  icon: ReactNode;
  hint?: string;
  required?: boolean;
  files: File[];
  onDrop: (files: File[]) => void;
  maxFiles?: number;
};

export function UploadCard({
  title,
  icon,
  hint,
  required = false,
  files,
  onDrop,
  maxFiles = 1,
}: Props) {
  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
      <div className="flex items-center gap-2 mb-4">
        {icon}
        <h3 className="text-lg font-semibold text-slate-900">{title}</h3>
        <span className={`text-xs ml-auto ${required ? "text-red-500" : "text-slate-500"}`}>
          {hint ?? (required ? "Required" : "Optional")}
        </span>
      </div>
      <Dropzone
        maxFiles={maxFiles}
        onDrop={onDrop}
        src={files}
        className="border-2 border-dashed border-[#d9ddcf] hover:border-[#4c956c] hover:bg-[#4c956c]/10 transition-all rounded-xl bg-white/60"
      >
        <DropzoneEmptyState />
        <DropzoneContent />
      </Dropzone>
      {files.length > 0 && (
        <p className="text-sm text-slate-600 mt-3">
          {files.length} file{files.length !== 1 ? "s" : ""} added
        </p>
      )}
    </div>
  );
}
